(2, 'ANNOUNCEMENT AND NOTIFICATIONS', 'Release of Non-Eligible Learners for Readmission of KYP SDCs & KYP for ITI SDCs', '', '', '<p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">Dear SDCs,</p><p class=\"has-text-align-justify\" style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; text-align: justify; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">Non-Eligible Learner i.e., those learners for which a Hall Ticket was never generated in all Three Attempt for any of the three paper (BS-CIT, BS-CLS &amp; BS-CSS) from the below-mentioned batches has been released for readmission in&nbsp;<strong style=\"-webkit-font-smoothing: antialiased;\">May 2023</strong>&nbsp;or<strong style=\"-webkit-font-smoothing: antialiased;\">&nbsp;Future Batches.</strong></p><p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">KYP: November 2022:&nbsp;<strong style=\"-webkit-font-smoothing: antialiased;\">3650</strong>&nbsp;Learners</p><p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">KYP ITI: August 2022:&nbsp;<strong style=\"-webkit-font-smoothing: antialiased;\">14</strong>&nbsp;Learners</p>', '30-04-2023', 1),
(3, 'ANNOUNCEMENT AND NOTIFICATIONS', 'KYP Final Exam Result of the “15th & 17th April 2023 Exam Event” has been declared.', '', '', '<p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">Dear KYP SDC,</p><p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">KYP Final Exam Result of the “15th&nbsp;&amp; 17th&nbsp;April 2023 Exam Event” has been declared.</p><p style=\"-webkit-font-smoothing: antialiased; border: 0px; font-family: Oswald, sans-serif; font-size: 17px; line-height: 28.9px; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; padding: 0px; color: rgb(17, 17, 17); background-color: rgb(241, 241, 241);\">Follow the below-mentioned path to check the KYP Final Exam Result:</p>', '30-04-2023', 1);
