INSERT INTO `webpage` (`id`, `cid`, `name`, `title`, `img`, `vdo`, `des`, `date`, `status`) VALUES
(10, 5, 'About Us', '', '', '', '<p><b>QUICK AND EASY TO INCREASE YOUR ADMISSIONS</b></p><p><b style=\"color: rgb(156, 0, 255);\">Increasing admissions can be a challenging task, but here are some tips that might help:</b><br></p><p>Enhance Your Online Presence: In today\'s digital age, having a strong online presence is crucial. Ensure that your website is up-to-date, user-friendly, and search engine optimized. You can also use social media platforms to connect with potential students and engage with them.</p><p>Utilize Referral Programs: Encourage your current students, faculty, and staff to refer potential students to your institution. You can offer incentives for successful referrals.</p><p>Attend Education Fairs and Conferences: Attending education fairs and conferences can provide you with an opportunity to network with potential students, parents, and other education professionals. Make sure to have attractive displays and brochures to promote your institution.</p><p>Offer Flexible and Convenient Options: Many students have busy schedules, so offering flexible and convenient options, such as&nbsp; hybrid programs, can be attractive to them.</p><p>Provide Excellent Service: Excellent service can help build a positive reputation for your institution and attract more students. Ensure that you have a responsive and helpful admissions team that can answer queries promptly and provide excellent support throughout the admission process.</p><p>By implementing these tips, you can increase your admissions and attract more students to your institution.</p>', '12-06-2022', 1),
(12, 5, 'Ethics', '', '', '', '<h5><div style=\"text-align: center;\"><span style=\"font-size: 1.25rem;\">We are committed to running a responsible and transparent business, setting high ethical standards for our industry, service and supply chain, and embracing corporate governance best practices.</span></div><div style=\"text-align: center;\"><span style=\"font-size: 1.25rem;\">We help clients succeed and connect a wide range of people with the opportunities and dignity of work and service.</span></div><div style=\"text-align: center;\"><span style=\"font-size: 1.25rem;\">Yuva Helpline and its subsidiaries and affiliates worldwide are committed to conducting our business with honesty, integrity, trustworthiness, and accountability.</span></div></h5>', '13-06-2022', 0),
(13, 5, 'Value & Vision', '', '', '', '<h5 style=\"text-align: center;\">We believe that meaningful, sustainable and solid services have the power to change the world. And we promise to serve you in various sectors in a simple way.Our vision is to lead in the creation and delivery of service solutions and services that enable our customers to win in the changing world of service.</h5>', '14-06-2022', 1),
(15, 8, 'Admission', '', '', '', '<p>Coming Soon...</p>', '14-06-2022', 1),
(16, 8, 'Rules & Regulation', '', '', '', '<p>Coming Soon....</p>', '14-06-2022', 1),
(17, 9, 'Infrastructure', '', '', '', '', '14-06-2022', 1),
(19, 9, 'Computer Lab', '', '', '', '<p>Coming Soon...</p>', '14-06-2022', 1),
(20, 5, 'Director Message', '', '', '', '<div align=\"justify\" style=\"box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;,sans-serif; font-size: 13px; font-style: normal; font-variant: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: justify; text-decoration: none; text-indent: 0px; text-transform: none; -webkit-text-stroke-width: 0px; white-space: normal; word-spacing: 0px;\"><h3 style=\"box-sizing: border-box; font-size: 1.75rem; font-weight: 500; line-height: 1.2; margin-bottom: 0.5rem; margin-top: 0px;\"><b style=\"box-sizing: border-box; font-weight: bolder;\">Dear Student,</b></h3><h3 style=\"box-sizing: border-box; font-size: 1.75rem; font-weight: 500; line-height: 1.2; margin-bottom: 0.5rem; margin-top: 0px;\"><b style=\"box-sizing: border-box; font-weight: bolder;\"><br style=\"box-sizing: border-box;\"></b></h3>We welcome you to our GSIIT Institute. We at <span style=\"display: inline !important; float: none; background-color: rgb(255, 255, 255); color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;,sans-serif; font-size: 13px; font-style: normal; font-variant: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: justify; text-decoration: none; text-indent: 0px; text-transform: none; -webkit-text-stroke-width: 0px; white-space: normal; word-spacing: 0px;\">GSIIT Institute</span> strive to offer you a better life-with the help of our instructions and there after. This is why we lay emphasis on providing you with better courses infrastructure and quality education in the field of Information Technology and Infrastructure management services. We see <span style=\"display: inline !important; float: none; background-color: rgb(255, 255, 255); color: rgb(0, 0, 0); font-family: &quot;Open Sans&quot;,sans-serif; font-size: 13px; font-style: normal; font-variant: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: justify; text-decoration: none; text-indent: 0px; text-transform: none; -webkit-text-stroke-width: 0px; white-space: normal; word-spacing: 0px;\">GSIIT Institute </span>as not just an IT Institution, but a way of leading and molding for a Better Life.<br style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\">Today as we all stand as a witness to the IT revolution we have seen and experienced the invisible role of computers in our personal and professional life. Just with the click of a button, people are executing big ideas, enjoying shopping without dealing with congested mob, seeking entertainment and recreation, meeting strangers without travelling and above all, connecting with their loved ones with no consideration of how far they are placed. Today it\'s easy to marvel how far we’ve come. Our phone talk to or TV’s to record our shows. Doctor in America diagnose patients in Poland. Social Network helps companies to maintain their QMS (Quality Management System) to improve their customer service.<br style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\">Industries, economics and nations are running on this gigantic network. Eventually trees will talk to network and tell the scientist about climate change. Traffic light will talk to cars and cars will talk to road sensors for increasing traffic efficiency. It’s phenomenon we call the internet of everything an unprecedented opportunity for today business and it is the need that is generating the need for more and more learners every day.<br style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\">We would like to re assure you, as to why choosing computer courses from GSIIT Institute are the right choice to seek a better life. 62% of students in India feel that their post-secondary studies have enhanced employment opportunities for them. 38% of employers say, a skill shortage is leading to entry level vacancies.<br style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\">By these facts we would like to stress on the importance of employability and skills development before you join your respective industry. By coming to GSIIT Institute, you have chosen the best for computer courses and services. I once again welcome you to aboard this journey, and wish you a better life and a great future ahead.<br style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\"><h3 style=\"box-sizing: border-box; font-size: 1.75rem; font-weight: 500; line-height: 1.2; margin-bottom: 0.5rem; margin-top: 0px;\"><span style=\"box-sizing: border-box; color: rgb(255, 0, 0);\"><b style=\"box-sizing: border-box; font-weight: bolder;\"><span style=\"box-sizing: border-box;\" arial=\"\" black\";\"=\"\">All the best!</span></b></span></h3></div>', '28-06-2022', 1),
